import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Module http","description":"该模块提供了与 LLM（大语言模型）HTTP 通信相关的核心基础设施。它负责管理环境配置的读取（如 API 密钥和基础 URL）、构建和发起同步与异步 HTTP 请求、处理返回的原始响应或错误（通过 LLMError 类型），并支持可选的请求速率限制机制（通过初始化/关闭函数以及内部信号量）。模块的公开接口主要位于 clore::net 命名空间下，包含 initialize_llm_rate_limit、shutdown_llm_rate_limit 以及 LLMError 等；同时公开了 detail 命名空间内的若干实现辅助函数和结构体（如 perform_http_request、EnvironmentConfig 等），供库内部或紧密协作的模块使用。这些设计使上层调用者能够以统一的方式执行 LLM HTTP 操作，而无需直接处理底层网络细节。","frontmatter":{"title":"Module http","description":"该模块提供了与 LLM（大语言模型）HTTP 通信相关的核心基础设施。它负责管理环境配置的读取（如 API 密钥和基础 URL）、构建和发起同步与异步 HTTP 请求、处理返回的原始响应或错误（通过 LLMError 类型），并支持可选的请求速率限制机制（通过初始化/关闭函数以及内部信号量）。模块的公开接口主要位于 clore::net 命名空间下，包含 initialize_llm_rate_limit、shutdown_llm_rate_limit 以及 LLMError 等；同时公开了 detail 命名空间内的若干实现辅助函数和结构体（如 perform_http_request、EnvironmentConfig 等），供库内部或紧密协作的模块使用。这些设计使上层调用者能够以统一的方式执行 LLM HTTP 操作，而无需直接处理底层网络细节。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/http/index.md","filePath":"zh/clore/modules/http/index.md"}'),i={name:"zh/clore/modules/http/index.md"};function c(l,e,d,s,n,h){return t(),o("div",null,[...e[0]||(e[0]=[r("",197)])])}const m=a(i,[["render",c]]);export{u as __pageData,m as default};
